return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=(n%10==1 && n%100!=11 ? 0 : n%10>=2 && (n%100<10 || n%100>=20) ? 1 : 2);','language'=>'lt_LT','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Atnaujinkite įskiepį TranslatePress - Multilingual iki %1$s ar naujesnės versijos, kad %2$s veiktų tinkamai.','Please install and activate the TranslatePress - Multilingual plugin'=>'Įdiekite ir aktyvuokite įskiepį TranslatePress - Multilingual','Install & Activate'=>'Įdiegti ir aktyvuoti','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Atnaujinkite TranslatePress - Multilingual iki %2$s ar naujesnės versijos. Jūsų įdiegta TranslatePress - Multilingual versija nebėra suderinama su dabartine %1$s versija.','All TranslatePress functionalities are disabled until then.'=>'Visos TranslatePress funkcijos išjungtos iki tol.','Update Now'=>'Atnaujinti dabar','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Šis TranslatePress priedas perkeltas į pagrindinį įskiepį ir nebenaudojamas. Galite jį ištrinti.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> veikimui reikalinga bent PHP 5.6.20+ versija. Tai yra <a href="%s">naujausios WordPress versijos minimalus reikalavimas</a>. Susisiekite su serverio administratoriumi, kad atnaujintų jūsų PHP versiją.','Advanced'=>'Išplėstiniai','Settings saved.'=>'Nustatymai išsaugoti.','Are you sure you want to remove this item?'=>'Ar tikrai norite pašalinti šį elementą?','Remove'=>'Pašalinti','Add'=>'Pridėti','Select...'=>'Pasirinkite...','[%s] Low TranslatePress AI Words'=>'[%s] Mažai TranslatePress AI žodžių','upgrade your plan or get extra AI Words'=>'patobulinkite savo planą arba įsigykite papildomų AI žodžių','upgrade your plan'=>'patobulinkite savo planą','TranslatePress AI words are running low on your site.'=>'Jūsų svetainėje senka TranslatePress AI žodžiai.','Current status: %s words remaining'=>'Dabartinė būsena: liko %s žodžių','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Kai baigsis likę AI žodžiai, automatinis vertimas per TranslatePress AI bus sustabdytas.','To continue translating your content, please %1$s over at %2$s'=>'Norėdami toliau versti savo turinį, prašome %1$s adresu %2$s','Manage Notification: %s'=>'Valdyti pranešimą: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Yra nauja %1$s versija. %2$sPeržiūrėti %3$s versijos informaciją%4$s arba %5$satnaujinti dabar%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Yra nauja %1$s versija. %2$sPeržiūrėti %3$s versijos informaciją%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Norėdami įgalinti atnaujinimus, prašome %1$sįvesti savo licencijos raktą%2$s. Reikia licencijos rakto? %3$sĮsigyti dabar%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Norėdami įgalinti atnaujinimus, eikite į %1$slicencijos puslapį%2$s ir patikrinkite, ar turite galiojančią licenciją.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Norėdami įgalinti atnaujinimus, jūsų licencija turi būti atnaujinta. Eikite į %1$sTranslatePress Account%2$s puslapį ir prisijunkite, kad atnaujintumėte.','You do not have permission to install plugin updates'=>'Jūs neturite leidimo diegti papildinių atnaujinimus','Error'=>'Klaida','Your TranslatePress license key is invalid or missing.'=>'Jūsų TranslatePress licencijos raktas neteisingas arba jo nėra.','Your license key expired on %s.'=>'Jūsų licencijos raktas baigė galioti %s.','Your license key has been disabled.'=>'Jūsų licencijos raktas išjungtas.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Jūsų licencijos raktas išjungtas šiam URL. Įjunkite jį iš naujo adresu <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Tvarkyti svetaines.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Licencijos rakto neatitikimas.</strong> Įvesta licencija neatitinka įdiegtos TranslatePress versijos.</p><p>Patikrinkite, ar iš savo TranslatePress paskyros įdiegėte teisingą versiją, skirtą jūsų licencijai.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Jei įdiegėte tik nemokamą papildinį, bet pridėjote mokamą licenciją, prašome įdiegti mokamą papildinį iš savo TranslatePress paskyros.','Your license key has reached its activation limit.'=>'Jūsų licencijos raktas pasiekė aktyvavimo limitą.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Atnaujinkite savo planą, kad pridėtumėte daugiau svetainių. %1$sAtnaujinti dabar%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Ši svetainė jau suaktyvinta su nemokama licencija. Kiekviena svetainė gali naudoti tik vieną nemokamą licenciją.','An error occurred, please try again.'=>'Įvyko klaida, prašome bandyti dar kartą.','You have successfully activated your license'=>'Sėkmingai aktyvavote savo licenciją','Others'=>'Kita','Restrict by Language'=>'Apriboti pagal kalbą','Exclude from Language'=>'Išskirti iš kalbos','Restrict element to language'=>'Apriboti elementą kalbai','Show this element only in one language.'=>'Rodyti šį elementą tik vienoje kalboje.','Enable translation'=>'Įjungti vertimą','Allow translation to the corresponding language only if the content is written in the default language.'=>'Leisti vertimą į atitinkamą kalbą tik tuo atveju, jei turinys parašytas numatytojoje kalboje.','Select language'=>'Pasirinkti kalbą','Choose in which language to show this element.'=>'Pasirinkti, kuria kalba rodyti šį elementą.','Exclude element from language'=>'Išskirti elementą iš kalbos','Exclude this element from specific languages.'=>'Išskirti šį elementą iš konkrečių kalbų.','Select languages'=>'Pasirinkti kalbas','Choose from which languages to exclude this element.'=>'Pasirinkti, iš kurių kalbų išskirti šį elementą.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Šis elementas vis tiek bus matomas, kai verčiate savo svetainę per vertimo redaktorių.','The content of this element should be written in the default language.'=>'Šio elemento turinys turėtų būti parašytas numatytojoje kalboje.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> aptiko SQL klaidų. <a href="%s" title="View TranslatePress SQL Errors">Peržiūrėkite klaidas</a>.','Automatic translation has been disabled.'=>'Automatinis vertimas išjungtas.','Dismiss this notice.'=>'Atmesti šį pranešimą.','Logged errors'=>'Registruotos klaidos','These are the most recent 5 errors logged by TranslatePress:'=>'Tai 5 naujausios TranslatePress registruotos klaidos:','Yes'=>'Taip','Why are these errors occuring'=>'Kodėl kyla šios klaidos','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Jei TranslatePress aptinka ką nors negerai vykdant užklausas jūsų duomenų bazėje, ji gali išjungti Automatinio vertimo funkciją, kad išvengtų papildomų mokesčių iš Google/DeepL. Automatinis vertimas turi būti įjungtas rankiniu būdu, kai išsprendžiate problemas.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Aptiktos SQL klaidos gali kilti dėl įvairių priežasčių, įskaitant trūkstamas lenteles, trūkstamas SQL naudotojo teises kurti lenteles ar atlikti kitas operacijas, problemas po svetainės perkėlimo ar SQL serverio konfigūracijos pakeitimus.','What you can do in this situation'=>'Ką galite padaryti šioje situacijoje','Plan A.'=>'A planas.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Eikite į Nustatymai -> TranslatePress -> Bendrasis skirtukas ir išsaugokite nustatymus. Tai atgeneruos lenteles naudojant jūsų dabartinius SQL nustatymus. Patikrinkite, ar naršant svetainę išversta kalba nebekyla klaidų. Pažiūrėkite į klaidų laiko žymas, kad įsitikintumėte, jog nematote senų klaidų. Rodomos tik 5 naujausios klaidos.','Plan B.'=>'B planas.','If your problem isn\'t solved, try the following steps:'=>'Jei jūsų problema neišspręsta, pabandykite šiuos veiksmus:','Create a backup of your database'=>'Sukurkite duomenų bazės atsarginę kopiją','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Sukurkite kiekvienos vertimų lentelės, kurioje kyla klaidų, kopiją. Galite kopijuoti lentelę toje pačioje duomenų bazėje (pavyzdžiui, trp_dictionary_en_us_es_es_COPY) -- atlikite šį veiksmą tik tuo atveju, jei norite išsaugoti dabartinius vertimus','Remove the trouble tables by executing the DROP function on them'=>'Pašalinkite problemines lenteles, joms pritaikydami DROP funkciją','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Eikite į Nustatymai -> TranslatePress -> Bendrasis skirtukas ir išsaugokite nustatymus. Tai atgeneruos lenteles naudojant jūsų dabartinį SQL serverį.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Nukopijuokite atitinkamą turinį iš dubliuotų lentelių (pavyzdžiui, trp_dictionary_en_us_es_es_COPY) į naujai sugeneruotą lentelę (trp_dictionary_en_us_es_es) -- atlikite šį veiksmą tik tuo atveju, jei norite išsaugoti dabartinius vertimus','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Patikrinkite, ar viskas veikia. Jei kas nors nutiko ne taip, galite atkurti pirmame žingsnyje sukurtą atsarginę kopiją. Patikrinkite, ar naršant svetainę išversta kalba nebekyla klaidų. Pažiūrėkite į klaidų laiko žymas, kad įsitikintumėte, jog nematote senų klaidų. Rodomos tik 5 naujausios klaidos.','Plan C.'=>'C planas.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Jei jūsų problema vis dar neišspręsta, pabandykite paklausti savo prieglobos teikėjo apie klaidas. Dažniausia problema – trūkstamos SQL naudotojo teisės, pavyzdžiui, teisė kurti lenteles.','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Nepavyko įdiegti. Bandykite dar kartą iš <a href="%s" >Papildinių valdymo skydo.</a>','Active'=>'Aktyvus','Permission denied.'=>'Prieiga uždrausta.','Invalid nonce.'=>'Neteisingas nonce.','Settings scope unknown.'=>'Nustatymų sritis nežinoma.','Legacy disabled.'=>'Senasis režimas išjungtas.','Language Switcher'=>'Kalbos perjungiklis','Change language to %s'=>'Pakeisti kalbą į %s','Automatic Translation'=>'Automatinis vertimas','DeepL'=>'DeepL','Unsupported languages'=>'Nepalaikomos kalbos','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Pasirinktas automatinio vertimo variklis nepalaiko šių kalbų.<br>Vis dar galite rankiniu būdu versti puslapius šiomis kalbomis naudodami vertimo redaktorių.','API key validation failed.'=>'API rakto patvirtinimas nepavyko.','API key verification was successful.'=>'API raktas sėkmingai patvirtintas.','Please enter your Google Translate key.'=>'Įveskite savo Google Translate raktą.','Please enter your DeepL API key.'=>'Įveskite savo DeepL API raktą.','Not TranslatePress onboarding page.'=>'Ne TranslatePress pradinio nustatymo puslapis.','Step %s does not exist'=>'Žingsnis %s neegzistuoja','Welcome'=>'Sveiki','Add Languages'=>'Pridėti kalbas','Enable Addons'=>'Įjungti priedus','Finalize'=>'Užbaigti','Exit Setup'=>'Išeiti iš sąrankos','Upgrade'=>'Atnaujinti','Nothing here'=>'Čia nieko nėra','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Jūsų <strong>TranslatePress</strong> licencija nerasta arba netinkama. <br/>Prašome %1$sregistruoti savo kopiją%2$s, kad įjungtumėte automatinį svetainės vertimą per TranslatePress AI, premium priedus, automatinius atnaujinimus ir palaikymą. Reikia licencijos rakto? %3$sPirkite dabar%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Jūsų <strong>TranslatePress</strong> licencijos galiojimas baigsis %1$s. Prašome %2$sAtnaujinti savo licenciją%3$s, kad ir toliau gautumėte prieigą prie automatinių vertimų per TP AI, premium priedų, produktų atsisiuntimų ir automatinių atnaujinimų. %4$sAtnaujinti dabar%5$s','Error: '=>'Klaida: ','Something went wrong, please try again.'=>'Įvyko klaida, bandykite dar kartą.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Jūsų <strong>TranslatePress</strong> licencijos galiojimas pasibaigė. <br/>Prašome %1$sAtnaujinti savo licenciją%2$s, kad ir toliau gautumėte prieigą prie automatinių vertimų per TranslatePress AI, premium priedų, produktų atsisiuntimų ir automatinių atnaujinimų. %3$sAtnaujinti dabar %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Licencijos rakto neatitikimas. Įvesta licencija neatitinka įdiegtos <strong>%1$s</strong> versijos. <br/>Prašome patikrinti, ar iš savo %2$sTranslatePress paskyros%3$s įdiegėte teisingą licencijos versiją.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Jei turite įdiegtą tik nemokamą įskiepį, bet pridėjote mokamą licenciją, prašome įdiegti mokamą įskiepį iš savo TranslatePress paskyros.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Pasiekėte aktyvavimo limitą savo <strong>%1$s</strong> licencijos. <br/>Valdykite savo aktyvias svetaines iš %2$s savo paskyros %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Jūsų licencija šiam URL išjungta. Įjunkite ją iš naujo iš <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Valdyti svetaines.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'%1$s automatinis vertimas reikalauja aktyvios licencijos. Prašome %2$satnaujinti%3$s savo licenciją arba įsigyti naują %4$sčia%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Prašome %1$sįvesti%2$s savo licencijos raktą, kad įjungtumėte %3$s automatinį vertimą.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Jums likę mažiau nei 5 000 TranslatePress AI žodžių. Kad toliau automatiškai verstumėte savo svetainę, prašome %sįsigyti papildomų AI žodžių su nuolaida iš savo paskyros%s.',' Error: '=>' Klaida: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Ši svetainė jau aktyvuota naudojant nemokamą licenciją. Kiekviena svetainė gali naudoti tik vieną nemokamą licenciją. Prašome atnaujinti į premium planą, kad gautumėte daugiau TranslatePress AI žodžių iš %1$s savo paskyros %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Jūs neturite galiojančios <strong>TranslatePress</strong> licencijos. %1$sGaukite nemokamai%2$s, kad gautumėte prieigą prie TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>NAUJA:</strong> Čia yra <strong>Different Domain per Language</strong> priedas! Padidinkite savo pasaulinį SEO ir sukurkite vietinę patirtį naudodami šaliai būdingus domenus, tokius kaip .de arba .fr. Atnaujinkite į <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business arba Developer</a>, kad gautumėte prieigą prie jo ir daugiau premium privalumų!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>NAUJA:</strong> Čia yra <strong>Different Domain per Language</strong> priedas! Padidinkite savo pasaulinį SEO ir sukurkite vietinę patirtį naudodami šaliai būdingus domenus, tokius kaip .de arba .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Sužinoti daugiau</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Viršytas dienos mašininio vertimo simbolių limitas. Prašome patikrinti <strong>TranslatePress -> <a href="%s">Automatinis vertimas</a></strong> puslapį, kad gautumėte daugiau informacijos.','Marketing optin'=>'Rinkodaros sutikimas','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Sutikite gauti pranešimus apie saugumo ir funkcijų atnaujinimus bei nejautrią diagnostinę stebėseną.','TranslatePress Preferred User Language'=>'TranslatePress pageidaujama vartotojo kalba','Preferred language to navigate the site'=>'Pageidaujama svetainės naršymo kalba','The language is automatically set based by the last visited language by the user.'=>'Kalba automatiškai nustatoma pagal paskutinę vartotojo aplankytą kalbą.','Always use this language'=>'Visada naudoti šią kalbą','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Pažymėjus šį nustatymą, pageidaujama kalba liks aukščiau pasirinkta, be galimybės ją pakeisti išorinėje sąsajoje.<br>Ši kalba bus naudojama įvairiose operacijose, pavyzdžiui, siunčiant el. laišką vartotojui.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Sveiki! Atrodo, kad jau kurį laiką naudojate <strong>TranslatePress</strong>, kad verstumėte savo svetainę. Tai nuostabu! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Jei galėtumėte skirti kelias minutes įvertinti jį WordPress.org svetainėje, tai labai padėtų mums (ir pakeltų mano motyvaciją).','~ Razvan, developer of TranslatePress'=>'~ Razvan, TranslatePress kūrėjas','Rate TranslatePress on WordPress.org plugin page'=>'Įvertinti TranslatePress WordPress.org įskiepių puslapyje','Ok, I will gladly help!'=>'Gerai, mielai padėsiu!','No, thanks.'=>'Ne, ačiū.','Full Language Names'=>'Pilni kalbų pavadinimai','Short Language Names'=>'Trumpi kalbų pavadinimai','Flags with Full Language Names'=>'Vėliavėlės su pilnais kalbų pavadinimais','Flags with Short Language Names'=>'Vėliavėlės su trumpais kalbų pavadinimais','Only Flags'=>'Tik vėliavėlės','Full Language Names No HTML'=>'Pilni kalbų pavadinimai be HTML','Bottom Right'=>'Dešinėje apačioje','Bottom Left'=>'Apačioje kairėje','Top Right'=>'Viršuje dešinėje','Top Left'=>'Viršuje kairėje','Dark'=>'Tamsus','Light'=>'Šviesus','Deactivate'=>'Išjungti','Activate'=>'Įjungti','Invalid language code. Please try again.'=>'Neteisingas kalbos kodas. Bandykite dar kartą.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Kalbos kodai gali turėti tik A-Z a-z 0-9 - _ simbolius. Patikrinkite kalbos kodus TranslatePress bendrosiose nuostatose.','Error! Duplicate URL slug values.'=>'Klaida! Pasikartojančios URL slug reikšmės.','You cannot select 